### Steps to reproduce

I have go_router implemented for my web page and a redirect implemented.
In the example, when I go to `/callback`, go_router redirects to `/`, but displays the wrong uri path when I display `GoRouter.of(context).routeInformationProvider.value.uri.path`.

Workaround is to have `GoRouter.of(context).routeInformationProvider.value.uri.path` wrapped around a `FutureBuilder`.

Shouldn't redirecting be completely finished before building rest of the widget tree?

### Expected results

`GoRouter.of(context).routeInformationProvider.value.uri.path` should be the path we have been redirected to.

### Actual results

`GoRouter.of(context).routeInformationProvider.value.uri.path` is path before redirection.

### Code sample

<details open><summary>Code sample</summary>

```dart
import 'package:flutter/material.dart';
import 'package:go_router/go_router.dart';
import 'package:flutter_web_plugins/url_strategy.dart';

void main() {
  usePathUrlStrategy();

  runApp(const MainApp());
}

final _router = GoRouter(
  debugLogDiagnostics: true,
  redirect: (context, state) {
    return state.uri.path.endsWith('callback') ? '/' : null;
  },
  routes: [
    GoRoute(
      path: '/',
      builder: (context, state) {
        return const Center(
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text('Home'),
              UriWidget(), //Shows '/callback' when redirected from /callback
              UriWidgetDelayed(), //Shows '/' when redirected from /callback
            ],
          ),
        );
      },
    ),
  ],
);

class UriWidget extends StatelessWidget {
  const UriWidget({super.key});

  @override
  Widget build(BuildContext context) {
    final router = GoRouter.of(context);
    final path = router.routeInformationProvider.value.uri.path;
    return Text('Current path: $path');
  }
}

class UriWidgetDelayed extends StatefulWidget {
  const UriWidgetDelayed({super.key});

  @override
  State<UriWidgetDelayed> createState() => _UriWidgetDelayedState();
}

class _UriWidgetDelayedState extends State<UriWidgetDelayed> {
  @override
  Widget build(BuildContext context) {
    return FutureBuilder(
      future: Future.delayed(Duration.zero),
      // Builder gets called twice
      // first time output is `UriWidgetDelayed waiting: /callback`
      // second time output is `UriWidgetDelayed done: /`
      builder: (context, snapshot) {
        final router = GoRouter.of(context);
        final path = router.routeInformationProvider.value.uri.path;
        debugPrint('UriWidgetDelayed ${snapshot.connectionState.name}: $path');
        return Text('Current path: $path');
      },
    );
  }
}

class MainApp extends StatelessWidget {
  const MainApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp.router(
      routerConfig: _router,
    );
  }
}
