class KushkiService {
  KushkiService(
    this._httpClient,
    this.maxComunicationMilliseconds,
  );

  final Dio _httpClient;
  late final WebViewController controller;
  String? _chargeToken;
  ChargeTokenGenerationErrorNotification? _chargeTokenError;
  bool _loadingChargeToken = false;
  int currentComunicationMilliseconds = 0;
  int maxComunicationMilliseconds;

  Future<PaymentProviderData> getPaymentProviderData(Card card) async {
    var paymentToken = await _getSubscriptionChargeToken(card.cardToken);
    return PaymentProviderData(
      providerName: PaymentProvider.kushki,
      providerCardToken: card.cardToken,
      paymentToken: paymentToken,
      subscriptionMethod: card.subscriptionMethod,
    );
  }

  Future<String> _getSubscriptionChargeToken(String subscriptionId) async {
    try {
      currentComunicationMilliseconds = 0;
      _loadingChargeToken = true;
      await controller.runJavaScript(
          '''requestSubscriptionDeviceToken("$subscriptionId")''');
      var token = await _loadChargeToken();
      _chargeToken = null;
      return token;
    } on Exception catch (exception) {
      log('''[KushkiService]: Couldn't get card subscription token - $exception.''');
      _loadingChargeToken = false;
      rethrow;
    }
  }

  void setChargeToken(String token) {
    _chargeToken = token;
    _loadingChargeToken = false;
  }

  void setChargeTokenError(TokenGenerationError error) {
    var tokenGenerationErrorRequest =
        TokenGenerationErrorRequest(card: null, error: error);
    _chargeTokenError = ChargeTokenGenerationErrorNotification.fromProviderCode(
        tokenGenerationErrorRequest.error.providerCode);
    _loadingChargeToken = false;
  }

  Future<String> _loadChargeToken() async {
    if (_loadingChargeToken == true &&
        currentComunicationMilliseconds < maxComunicationMilliseconds) {
      currentComunicationMilliseconds++;
      return Future.delayed(
          const Duration(milliseconds: 100), _loadChargeToken);
    } else if (_loadingChargeToken == true &&
        currentComunicationMilliseconds >= maxComunicationMilliseconds) {
      throw createSubscriptionChargeTokenTimeoutError;
    }

    if (_chargeToken == null) {
      throw _chargeTokenError!;
    }
    return _chargeToken!;
  }
