It is fully reproducible in DartPad.

```dart
import 'package:flutter/material.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: Scaffold(
        body: Directionality(
          textDirection: TextDirection.ltr,
          child: ChipTextInput(),
        ),
      ),
    );
  }
}

class ChipTextInput extends StatefulWidget {
  const ChipTextInput({
    super.key,
    this.onChanged,
  });

  final ValueChanged<String>? onChanged;

  @override
  ChipTextInputState createState() => ChipTextInputState();
}

class ChipTextInputState extends State<ChipTextInput> {
  @override
  void initState() {
    super.initState();
    _keyWordsRegex = RegExp(r'\<(AABBCC|DDEEFF|GGHHII)\>');
    _controller = RichTextEditingController(_keyWordsRegex);
  }

  late final RichTextEditingController _controller;
  late final RegExp _keyWordsRegex;

  @override
  Widget build(BuildContext context) {
    return TextField(
      controller: _controller,
      onChanged: widget.onChanged,
    );
  }
}

class RichTextEditingController extends TextEditingController {
  RichTextEditingController(RegExp keyWordsRegex)
      : _keyWordsRegex = keyWordsRegex;

  final RegExp _keyWordsRegex;

  @override
  TextSpan buildTextSpan({
    required BuildContext context,
    TextStyle? style,
    required bool withComposing,
  }) {
    Iterable<RegExpMatch> matches = _keyWordsRegex.allMatches(text);
    List<InlineSpan> result = [];
    int lastEnd = 0;

    for (RegExpMatch match in matches) {
      int start = match.start;
      int end = match.end;

      if (lastEnd < start) {
        result.add(TextSpan(
          text: text.substring(lastEnd, start),
        ));
      }

      result.add(
        WidgetSpan(
          child: Container(
            decoration: BoxDecoration(
                border: Border.all(
              color: Colors.black,
            )),
            child: Text(
              text.substring(start, end),
            ),
          ),
        ),
      );

      lastEnd = end;
    }
    if (lastEnd < text.length) {
      result.add(TextSpan(
        text: text.substring(lastEnd),
      ));
    }
    return TextSpan(children: result);
  }
}

